// CDB APEX v33.0 — CVE-2018-25197 - PlayJoom 0.10.1 SQL Injection via catid Parameter
DeviceNetworkEvents
| where RemoteUrl has_any ("index.php")

// CDB APEX v33.0 — CVE-2018-25198 - eToolz 3.4.8.0 Denial of Service via Buffer Overflow
DeviceNetworkEvents
| where RemoteIP in ("3.4.8.0")

// CDB APEX v33.0 — Who is the Kimwolf Botmaster “Dort”?
DeviceNetworkEvents
| where RemoteIP in ("99.241.112.24")

// OR

DeviceNetworkEvents
| where RemoteUrl has_any ("gmail.com", "ocdsb.ca", "osint.industries")

// CDB APEX v33.0 — Arkanix Stealer: a C++ & Python infostealer
DeviceNetworkEvents
| where RemoteUrl has_any ("hvnc.py", "stealer.py", "utils.cpp")

// CDB APEX v33.0 — SentinelOne Intelligence Brief: Iranian Cyber Activity Outlook
DeviceNetworkEvents
| where RemoteUrl has_any ("www.sentinelone.com")

// CDB APEX v33.0 — CVE-2018-25199 OOP CMS BLOG 1.0 SQL Injection via search parameter
DeviceNetworkEvents
| where RemoteUrl has_any ("page.php", "posts.php", "search.php")

// CDB APEX v33.0 — Exploits and vulnerabilities in Q4 2025
DeviceNetworkEvents
| where RemoteUrl has_any ("cve.org", "ltmdm64.sys")

// CDB APEX v33.0 — Cisco flags ongoing exploitation of two recently patched Catalyst SD-WAN flaws
DeviceNetworkEvents
| where RemoteIP in ("20.12.5.3", "20.12.6.1", "20.15.4.2", "20.18.2.1", "20.9.8.2")

// CDB APEX v33.0 — Exploit for Path Traversal in Tp-Link Tapo_C260_Firmware
DeviceNetworkEvents
| where RemoteUrl has_any ("lfd.py", "requirements.txt", "tapo-c260-rce.git")

// CDB APEX v33.0 — Proactive Preparation and Hardening Against Destructive Attacks: 2026 Edition
DeviceNetworkEvents
| where RemoteIP in ("1.3.6.1", "2.5.29.37", "5.2.3.4", "5.5.7.3")

// OR

DeviceNetworkEvents
| where RemoteUrl has_any ("details.aspx", "gpo-listing-all.csv", "hostd.log", "pfirewall.log", "shell.log", "snapshot.removeall", "vim.event", "vpxa.log", "vpxd.log", "vshphere.local")

// CDB APEX v33.0 — CVE-2026-23925 - Unauthorized host creation via configuration.import API by low-
DeviceNetworkEvents
| where RemoteUrl has_any ("configuration.import")

DeviceNetworkEvents | where RemoteIP in ("1.3.6.1", "2.5.29.37", "5.2.3.4", "5.5.7.3")
