DeviceNetworkEvents | where RemoteUrl has_any ("details.aspx", "gpo-listing-all.csv", "hostd.log", "pfirewall.log", "shell.log", "snapshot.removeall", "vim.event", "vpxa.log", "vpxd.log", "vshphere.local")
